REQUIRED = {'agent_success', 'baseline_success', 'branch_count', 'case_id', 'known_steps', 'tool_choice_uncertain'}
REJECT = 'KEEP_DETERMINISTIC_WORKFLOW'

def assess(record: dict) -> str:
    absent = sorted(REQUIRED - record.keys())
    if absent:
        return "MISSING:" + ",".join(absent)
    contract_ok = not (not record["known_steps"] or record["agent_success"] > record["baseline_success"])
    return "PASS" if contract_ok else REJECT

